class ReportService:
    def __init__(self, db, mailer, logger):
        self.db = db
        self.mailer = mailer
        self.logger = logger

    def generate_and_send(self, user_id: int) -> None:
        data = self.db.fetch_report(user_id)
        self.logger.info(f'Report generated for user {user_id}')
        self.mailer.send(user_id, data)

import csv
from typing import Generator

def stream_transactions(filepath: str) -> Generator[dict, None, None]:
    with open(filepath, 'r', encoding='utf-8', newline='') as f:
        reader = csv.DictReader(f)
        for row in reader:
            yield row

for tx in stream_transactions('transactions_2024.csv'):
    process(tx)
